SourceCode.Declaration:
/// <summary>
/// Represents the ETGSPAIN Purchases Operation Table, used to manage purchase operations and related processes.
/// </summary>
public class ETGSPAINPurchOperationTable extends common
{
}

Method.Source:
/// <summary>
/// Retrieves the associated <c>InventTable</c> record linked to this operation.
/// </summary>
/// <param name="_itemId">The item ID to retrieve.</param>
/// <param name="_forUpdate">Whether the record should be locked for update.</param>
/// <returns>Returns the associated <c>InventTable</c> record.</returns>
public InventTable inventTable(
    ItemId  _itemId       = this.ItemId,
    boolean _forUpdate    = false)
{
    return InventTable::find(_itemId, _forUpdate);
}

/// <summary>
/// Finds a specific record in the <c>ETGSPAINPurchOperationTable</c> by operation ID.
/// </summary>
/// <param name="_operationId">The operation ID to find.</param>
/// <param name="_forUpdate">Whether the record should be locked for update.</param>
/// <returns>Returns the found record or null if not found.</returns>
static ETGSPAINPurchOperationTable find(ETGSPAINPurchOperationId  _ETGSPAINPurchOperationId,
                                    boolean             _forUpdate = false)
{
    ETGSPAINPurchOperationTable operationTable;

    if (_ETGSPAINPurchOperationId)
    {
        if (_forUpdate)
        {
            operationTable.selectForUpdate(_forUpdate);
        }

        select firstonly operationTable
            index hint OperationIdx
            where operationTable.OperationId == _ETGSPAINPurchOperationId;
    }

    return operationTable;
}

/// <summary>
/// Checks whether an operation exists in the <c>ETGSPAINPurchOperationTable</c>.
/// </summary>
/// <param name="_operationId">The operation ID to check.</param>
/// <returns>Returns true if the operation exists, otherwise false.</returns>
static boolean exist(ETGSPAINPurchOperationId  _ETGSPAINPurchOperationId)
{
    return _ETGSPAINPurchOperationId && (select firstonly RecId from ETGSPAINPurchOperationTable
                                        index hint OperationIdx
                                        where ETGSPAINPurchOperationTable.OperationId == _ETGSPAINPurchOperationId).RecId != 0;
}

/// <summary>
/// Initializes values for a new operation record.
/// </summary>
public void initValue()
{
    NumberSeq           numberSeq;
    ETGSPAINPurchOperationId num;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        numberSeq   = NumberSeq::newGetNum(NumberSeqModulePurchaseOrder::ETGSPAINnumRefOperationId());
        num         = numberSeq.num();

        this.OperationId = num;
    }
    super();
}

/// <summary>
/// Inserts a new operation record, creating an inventory batch from the operation.
/// </summary>
public void insert()
{
    super();
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        this.createInventBatchFromETGSPAINPurchOperation(this.OperationId,this.ItemId);
    }
}

/// <summary>
/// Creates an inventory batch based on the operation ID and item ID.
/// </summary>
/// <param name="_operationId">The operation ID.</param>
/// <param name="_itemId">The item ID.</param>
public void createInventBatchFromETGSPAINPurchOperation(ETGSPAINPurchOperationId _operationId, ItemId _itemId)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        InventBatch inventBatch;

        inventBatch.clear();
        inventBatch.initValue();
        inventBatch.inventBatchId   = this.OperationId;
        inventBatch.itemId          = this.ItemId;

        if (InventBatch::exist(inventBatch.itemId, inventBatch.inventBatchId))
        {
            throw error(strFmt("@ETGSPAINLabels:BatchnumOperationError",this.OperationId,this.ItemId));
        }
        else
        {
            inventBatch.insert();
        }
    }
}

/// <summary>
/// Modified field event handler. Validates field dependencies on the <c>InventSiteId</c>.
/// </summary>
/// <param name="_fieldId">The field ID that was modified.</param>
public void modifiedField(FieldId _fieldId)
{
    super(_fieldId);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        switch (_fieldId)
        {
            case fieldNum(ETGSPAINPurchOperationTable,InventSiteId):
            if (this.InventLocationId
             && this.InventSiteId != InventLocation::find(this.InventLocationId).InventSiteId)
                {
                    this.InventLocationId = '';
                }
                break;
        }
    }
}

/// <summary>
/// Validates fields to ensure correct values.
/// </summary>
/// <param name="_fieldIdToCheck">The field ID to validate.</param>
/// <returns>Returns true if the field is valid, otherwise false.</returns>    
public boolean validateField(FieldId _fieldIdToCheck)
{
    boolean ret = true;

    super(_fieldIdToCheck);

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        switch (_fieldIdToCheck)
        {
            case fieldNum(ETGSPAINPurchOperationTable, InventLocationId):

            if (this.InventSiteId && this.InventLocationId)
                {
                    if (InventLocation::find(this.InventLocationId).InventSiteId != this.InventSiteId)
                    {
                        ret = checkFailed (strFmt("@SYS104861",this.InventLocationId,this.InventSiteId));
                    }
                }
                break;
        }
    }
    return ret;
}

/// <summary>
/// Retrieves the inventory dimension record related to the operation.
/// </summary>
/// <param name="_agreementLineQuantityCommitment">The agreement line commitment to link dimensions with.</param>
/// <param name="_agreementHeader">The header information for the agreement.</param>
/// <returns>Returns the associated <c>InventDim</c> record.</returns>
public InventDim inventDimFromAgreementLine(AgreementLineQuantityCommitment _agreementLineQuantityCommitment,
                                            AgreementHeader                 _agreementHeader)
{
    InventDim inventDim;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        inventDim = _agreementLineQuantityCommitment.inventDim();

        inventDim.InventSiteId      = this.InventSiteId;
        inventDim.inventLocationId  = this.InventLocationId;

        InventBatch inventBatch = InventBatch::findOrCreate(this.OperationId,
                                                        this.ItemId,
                                                        _agreementHeader.DefaultAgreementLineExpirationDate);

        inventDim.inventBatchId     = inventBatch.inventBatchId;

        PurchAgreementHeader    purchAgreementHeader    = PurchAgreementHeader::find(_agreementHeader.RecId);
        SalesAgreementHeader    salesAgreementHeader    = SalesAgreementHeader::find(_agreementHeader.RecId);
        InventSerialId          inventSerialAgreement   = purchAgreementHeader.PurchNumberSequence ? purchAgreementHeader.PurchNumberSequence : salesAgreementHeader.SalesNumberSequence;

        if (inventSerialAgreement)
        {
            InventSerial inventSerial = InventSerial::findOrCreate(inventSerialAgreement, this.ItemId);

            if (inventSerial)
            {
                inventDim.inventSerialId = inventSerial.InventSerialId;
            }
        }

        inventDim = InventDim::findOrCreate(inventDim);
    }
    return inventDim;
}

/// <summary>
/// Determines if the operation has associated packing slips (i.e., executions).
/// </summary>
/// <returns>Returns true if the operation has packing slips, otherwise false.</returns>
public boolean hasExecutions()
{
    boolean ret = false;

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        InventBatch inventBatch = InventBatch::find(this.OperationId, this.ItemId);

        if (inventBatch)
        {
            CustPackingSlipTrans    custPackingSlipTrans;
            VendPackingSlipTrans    vendPackingSlipTrans;
            InventDim               inventDimCust;
            InventDim               inventDimVend;

            select firstonly custPackingSlipTrans
            exists join inventDimCust
                where inventDimCust.inventDimId     == custPackingSlipTrans.InventDimId
                    && inventDimCust.inventBatchId  == inventBatch.inventBatchId;

            if (! custPackingSlipTrans)
            {
                select firstonly vendPackingSlipTrans
            exists join inventDimVend
                where inventDimVend.inventDimId     == vendPackingSlipTrans.InventDimId
                    && inventDimVend.inventBatchId  == inventBatch.inventBatchId;
            }

            ret = (custPackingSlipTrans || vendPackingSlipTrans) ? true : false;
        }
    }
    return ret;
}

/// <summary>
/// Performs a lookup for Operation IDs and Batch IDs based on the given table ID.
/// Filters the results based on the current operation status and batch information.
/// </summary>
/// <param name="_tableId">The table ID from which the lookup is being performed.</param>
/// <param name="_sender">The form control that initiated the lookup.</param>
/// <param name="_e">Event arguments related to the form control.</param>
public static void OperationIdBatchIdLookUp(TableId                 _tableId,
                                            FormControl             _sender, 
                                            FormControlEventArgs    _e)
{
    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        Query                   query;
        QueryBuildDataSource    qbdsInventBatchTable;
        QueryBuildDataSource    qbdsETGSPAINPurchOperationTable;
        QueryBuildRange         qbrETGSPAINOperationStatus;
        QueryBuildRange         qbrInventBatchId;
        SysTableLookup          sysTableLookUp;
        InventBatchId           inventBatchId = _sender.valueStr();

        switch (_tableId)
        {
            case tableNum(PurchAgreementHeader):
            case tableNum(SalesAgreementHeader):
                query = new Query(queryStr(ETGSPAINPurchOperationTableCreateQuery));

                sysTableLookup = SysTableLookup::newParameters(tablenum(ETGSPAINPurchOperationTable),_sender);

                sysTableLookup.addLookUpField(fieldNum(ETGSPAINPurchOperationTable, OperationId));
                sysTableLookup.addLookUpField(fieldNum(ETGSPAINPurchOperationTable, Name));
                sysTableLookup.addLookUpField(fieldNum(ETGSPAINPurchOperationTable, OperationStatus));
                break;
            default:
                break;
        }

        qbdsETGSPAINPurchOperationTable  = SysQuery::findOrCreateDataSource(query, tableNum(ETGSPAINPurchOperationTable));
        qbrETGSPAINOperationStatus       = SysQuery::findOrCreateRange(qbdsETGSPAINPurchOperationTable, fieldNum(ETGSPAINPurchOperationTable, OperationStatus));
        qbrETGSPAINOperationStatus.value(SysQuery::valueNot(ETGSPAINOperationStatus::Closed));

        qbdsInventBatchTable        = SysQuery::findOrCreateDataSource(query, tableNum(InventBatch));
        qbrInventBatchId            = SysQuery::findOrCreateRange(qbdsInventBatchTable, fieldNum(InventBatch, InventBatchId));
        qbrInventBatchId.value(inventBatchId);

        sysTableLookup.parmQuery(query);
        sysTableLookup.performFormLookup();

        FormControlCancelableSuperEventArgs ce = _e as FormControlCancelableSuperEventArgs;
        ce.CancelSuperCall();
    }
}

/// <summary>
/// Validates if the operation can be deleted.
/// </summary>
/// <returns>Returns true if deletion is allowed, otherwise false.</returns>
public boolean validateDelete()
{
    boolean ret;

    ret = super();

    if(CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        InventTrans invenTrans;
        InventDim inventDim;

        select firstonly RecId from invenTrans
        exists join inventDim
        where inventDim.InventDimId     == invenTrans.InventDimId
            && inventDim.InventBatchId  == this.OperationId;

        if (invenTrans.RecId)
        {
            ret = checkFailed("@ETGSPAINLabels:OperationDeleteError");
        }
    }

    return ret;
}
